// ── Clean & Standardize ─────────────────────────────────────────────────
// This node processes items from all 3 sources and outputs a
// unified, clean record for each item.

const seen = new Set();
const cleaned = [];

const cloudKeywords = [
  'cloud', 'aws', 'azure', 'gcp', 'kubernetes', 'terraform',
  'devops', 'docker', 'lambda', 'serverless', 'pipeline',
  'certification', 'architect', 'engineer', 'data', 'storage',
  'compute', 'networking', 'security', 'iam', 'vpc', 's3',
  'bigquery', 'pubsub', 'cloudwatch', 'ec2', 'rds'
];

function detectPlatform(text) {
  const t = (text || '').toLowerCase();
  if (t.includes('aws') || t.includes('amazon'))   return 'AWS';
  if (t.includes('azure') || t.includes('microsoft')) return 'Azure';
  if (t.includes('gcp') || t.includes('google cloud')) return 'GCP';
  if (t.includes('kubernetes') || t.includes('k8s')) return 'Kubernetes';
  return 'Multi-Cloud';
}

function extractSkills(text) {
  const t = (text || '').toLowerCase();
  return cloudKeywords
    .filter(k => t.includes(k))
    .slice(0, 5)
    .join(', ') || 'cloud-general';
}

function standardizeDate(raw) {
  try {
    const d = new Date(raw);
    if (isNaN(d.getTime())) return new Date().toISOString().slice(0, 10);
    return d.toISOString().slice(0, 10);
  } catch (_) {
    return new Date().toISOString().slice(0, 10);
  }
}

for (const item of $input.all()) {
  const j = item.json;

  // Skip empty items
  if (!j || Object.keys(j).length === 0) continue;

  // Extract fields regardless of which source the item came from
  const title   = (j.title   || j.name    || j.job_title  || '').trim();
  const summary = (j.summary || j.content || j.description || j.body || '').trim();
  const link    = (j.link    || j.url     || j.source_url  || '').trim();
  const rawDate = j.pubDate  || j.date    || j.published   || j.isoDate || '';
  const sourceName = j._source || j.source || (link.includes('aws') ? 'AWS Blog' : link.includes('google') ? 'Google Cloud Blog' : 'Cloud Jobs Dataset');

  if (!title) continue;   // must have a title

  // Deduplicate by title
  const key = title.toLowerCase().replace(/\s+/g, ' ');
  if (seen.has(key)) continue;
  seen.add(key);

  const fullText = `${title} ${summary}`;

  cleaned.push({
    title,
    platform:       detectPlatform(fullText),
    skill_tags:     extractSkills(fullText),
    summary:        summary.slice(0, 200).replace(/[\r\n]+/g, ' '),
    source:         sourceName,
    source_url:     link,
    date:           standardizeDate(rawDate),
    record_quality: (title && rawDate && link) ? 'complete' : 'partial'
  });
}

// Sort by date descending
cleaned.sort((a, b) => b.date.localeCompare(a.date));

return cleaned.map(c => ({ json: c }));

// ── Quality Check ────────────────────────────────────────────────────────
// Log quality stats and flag any records missing critical fields.
const items = $input.all();
const total = items.length;
const complete = items.filter(i => i.json.record_quality === 'complete').length;
const pct = total > 0 ? Math.round((complete / total) * 100) : 0;

console.log(`Quality check: ${complete}/${total} complete records (${pct}%)`);

if (total < 50) {
  console.warn('WARNING: fewer than 50 records collected. Check data sources.');
}

// Pass all items through unchanged — we're just logging
return items;
